#include <bits/stdc++.h>
using namespace std;
int main(){
    long long n,a,m=-1,c=0;
    cin>>n>>a;
    long long d[n];
    for(int i=0;i<n;i++){
         cin>>d[i];
    }
    sort(d,d+n);
    for(int i=0;i<n-1;i++){
        for(int j=i+1;j<n;j++){
            if(d[j]-d[i]==a){
                c++;
            }
            else if(d[i]-d[j]>a){
                break;
            }
        }
    }
    cout<<c;
    return 0;
}
